#include <stdio.h>
#include <stdlib.h>

#define MX 10001

int main() {
    int n;
    scanf("%d", &n);

    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    int Hash[MX] = {0};

    int ans = 0;
    for (int i = 0; i < n; i++) {
        if ((long long)a[i] * a[i] < MX) {
            ans += Hash[a[i] * a[i]];
        }
        Hash[a[i]]++;
    }

    printf("%d", ans);

    return 0;
}

