import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        String a = scanner.next();
        String b = scanner.next();

        Map<Character, Integer> am = new HashMap<>();
        Map<Character, Integer> bm = new HashMap<>();

        for (int i = 0; i < n; i++) {
            am.put(a.charAt(i), am.getOrDefault(a.charAt(i), 0) + 1);
            bm.put(b.charAt(i), bm.getOrDefault(b.charAt(i), 0) + 1);
        }
        boolean flag = true;
        for (Map.Entry<Character, Integer> entry : am.entrySet()) {
            if (!bm.containsKey(entry.getKey()) || !bm.get(entry.getKey()).equals(entry.getValue())) {
                flag = false;
                break;
            }
        }

        if (flag) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }

        scanner.close();
    }
}
